```javascript
// Function to show toast
function showToast(message, type = 'success') {
  const toast = document.getElementById('toast');
  toast.textContent = message;
  toast.className = `fixed bottom-4 right-4 py-2 px-4 rounded shadow-md transition-opacity duration-300 ${type === 'success' ? 'bg-green-500' : (type === 'sync' ? 'bg-blue-500' : 'bg-gray-500')} text-white`;
  toast.classList.remove('hidden');
  setTimeout(() => {
    toast.classList.add('hidden');
  }, 3000);
}
```

